sql:
SELECT AVG(region_area) AS average_region_area
FROM regions
WHERE classification_system = 'R5_REGION';

SELECT region_name
FROM regions
WHERE region_area > 500000;

SELECT COUNT(country_id)
FROM country_regions
WHERE region_id = 1;

external_knowledge:
; Hierarchy implies a tree-like structure, where top-level regions are at the root, and child regions branch out from them; 
; Estimated population vs total population: Estimated population is a projected figure, while total population is calculated by summing up the population of countries within a region; 
; Geographical data: Area is provided in square kilometers.

